def generate_candidates(existing: set[str], rng: random.Random) -> list[Candidate]:
    from refill_common import interleave_candidates, is_filler_text

    out: list[Candidate] = []
    for q, ans, wrong, diff in FACTS:
        if is_filler_text(q) or "വിഷയം-" in ans:
            continue
        _add(out, existing, rng, q, ans, wrong + [ans], diff)
    return interleave_candidates(out, rng)
